function StoryPrompt() {
  const genres = ['Sci-Fi','Fantasy','Mystery','Romance','Horror','Thriller','Comedy','Drama'];
  const characters = ['a retired spy','a time-traveling barista','an alien archaeologist','a ghostwriter for the dead','a robot learning to paint','a chef who can taste memories','a librarian with a secret','a musician who hears colors'];
  const settings = ['a city built inside a giant tree','a space station at the edge of a black hole','a small town where no one sleeps','a library containing every book never written','a submarine in a methane ocean','a marketplace between dimensions','a house that rearranges itself','a train that stops at different decades'];
  const conflicts = ['must deliver a message that could start a war','discovers their reflection is plotting against them','has 24 hours to solve a murder they will commit','finds a door in their basement that leads to yesterday','inherits a curse that makes everyone tell them the truth','must choose between saving one person or a million','realizes they are a character in someone else's dream','has to teach an AI what it means to be human'];

  const [prompt, setPrompt] = React.useState('');

  const generate = ()=>{
    const g = genres[Math.floor(Math.random()*genres.length)];
    const c = characters[Math.floor(Math.random()*characters.length)];
    const s = settings[Math.floor(Math.random()*settings.length)];
    const x = conflicts[Math.floor(Math.random()*conflicts.length)];
    setPrompt(`<strong>Genre:</strong> ${g}<br/><strong>Character:</strong> ${c}<br/><strong>Setting:</strong> ${s}<br/><strong>Conflict:</strong> ${x}`);
  };

  React.useEffect(()=>generate(),[]);

  return (
    <div style={{padding:20,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:12}}>Story Prompt</div>
      <div style={{flex:1,padding:16,background:'#f8f8f8',borderRadius:12,marginBottom:12,lineHeight:1.6,fontSize:14,overflow:'auto'}}
        dangerouslySetInnerHTML={{__html:prompt}}/>
      <button onClick={generate}
        style={{padding:'10px',borderRadius:8,background:'#AF52DE',color:'#fff',border:'none',cursor:'pointer',fontSize:14,fontWeight:600}}>
        New Prompt
      </button>
    </div>
  );
}
render(<StoryPrompt/>);
